import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../models/product_model.dart'; final cartProvider = StateNotifierProvider<CartNotifier, CartState>((ref)=>CartNotifier()); class CartItem { final Product product; int quantity; CartItem({required this.product, this.quantity=1}); } class CartState { final List<CartItem> items; double get total => items.fold(0, (s,i)=>s+i.product.unitPrice*i.quantity); CartState({this.items=const[]}); CartState copyWith({List<CartItem>? items}) => CartState(items: items??this.items); } class CartNotifier extends StateNotifier<CartState> { CartNotifier() : super(CartState()); void add(Product p) { final idx = state.items.indexWhere((i)=>i.product.sku==p.sku); if(idx!=-1) { final newItems = [...state.items]; newItems[idx].quantity++; state = state.copyWith(items: newItems); } else { state = state.copyWith(items: [...state.items, CartItem(product: p)]); } } void remove(String sku) { state = state.copyWith(items: state.items.where((i)=>i.product.sku!=sku).toList()); } void clear() => state = CartState(); }
